I cannot directly generate a 3D file (like .obj or .fbx) or render a video file. However, I can provide you with the **complete code** to generate and render a 3D house in your browser right now using **Three.js**.

You can copy the code below, save it as an `.html` file (e.g., `house.html`), and open it in any modern web browser to see the result.

### 3D House Generator (HTML + Three.js)

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMat = new THREE.MeshStandardMaterial({ color: 0xE0E0E0 }); // White walls
        const roofMat = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const glassMat = new THREE.MeshStandardMaterial({ color: 0xADD8E6, transparent: true, opacity: 0.6 });
        const doorMat = new THREE.MeshStandardMaterial({ color: 0x5C4033 });
        const windowMat = new THREE.MeshStandardMaterial({ color: 0x88ccff });

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, wallMat);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Walls
        const wallHeight = 4;
        const wallGeo = new THREE.BoxGeometry(10, wallHeight, 1);
        const wall1 = new THREE.Mesh(wallGeo, wallMat);
        wall1.position.set(0, wallHeight/2, 5);
        wall1.castShadow = true;
        wall1.receiveShadow = true;
        houseGroup.add(wall1);

        const wall2 = new THREE.Mesh(wallGeo, wallMat);
        wall2.position.set(0, wallHeight/2, -5);
        wall2.castShadow = true;
        wall2.receiveShadow = true;
        houseGroup.add(wall2);

        const wall3 = new THREE.Mesh(wallGeo, wallMat);
        wall3.rotation.y = Math.PI / 2;
        wall3.position.set(5, wallHeight/2, 0);
        wall3.castShadow = true;
        wall3.receiveShadow = true;
        houseGroup.add(wall3);

        const wall4 = new THREE.Mesh(wallGeo, wallMat);
        wall4.rotation.y = Math.PI / 2;
        wall4.position.set(-5, wallHeight/2, 0);
        wall4.castShadow = true;
        wall4.receiveShadow = true;
        houseGroup.add(wall4);

        // Roof
        const roofGeo = new THREE.ConeGeometry(9, 5, 4);
        const roof = new THREE.Mesh(roofGeo, roofMat);
        roof.position.y = wallHeight + 2.5;
        roof.rotation.y = Math.PI / 4;
        roof.castShadow = true;
        houseGroup.add(roof);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 3, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 1.5, 4.9);
        houseGroup.add(door);

        // Windows (Simple squares)
        const winGeo = new THREE.BoxGeometry(2, 1.5, 0.1);
        const win1 = new THREE.Mesh(winGeo, windowMat);
        win1.position.set(0, 3, 4.9);
        houseGroup.add(win1);

        const win2 = new THREE.Mesh(winGeo, windowMat);
        win2.position.set(0, 3, -4.9);
        houseGroup.add(win2);

        // Add House to Scene
        scene.add(houseGroup);

        // 6. Ground (Grass)
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const groundMat = new THREE.MeshStandardMaterial({ color: 0x4caf50 });
        const ground = new THREE.Mesh(groundGeo, groundMat);
        ground.rotation.x = -Math.PI / 2;
        ground.position.y = -0.51;
        ground.receiveShadow = true;
        scene.add(ground);

        // 7. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in Chrome, Firefox, or Edge.

### What this code does:
*   **Scene Setup:** Creates a 3D environment with a sky-blue background and fog.
*   **Lighting:** Adds a directional light (sun) that casts shadows and an ambient light for general visibility.
*   **Geometry:** Constructs a house using basic shapes (Boxes for walls/floor, Cone for the roof).
*   **Materials:** Applies different colors and textures (white walls, brown roof, transparent glass for windows).
*   **Interactivity:** Includes `OrbitControls`, allowing you to click and drag to rotate around the house and scroll to zoom in/out.
